// منطق نهایی تصمیم‌گیری و اعتبارسنجی
const aiResult = JSON.parse($node['OpenAI: OCR & Anomaly Check'].json.content);
const dbResult = $input.first().json;
const dupCount = parseInt(dbResult.dup_count || 0);

let finalStatus = 'approved';
let rejectionReason = 'None';

// 1. بررسی تکراری بودن
if (dupCount > 0) {
  finalStatus = 'flagged';
  rejectionReason = 'Duplicate invoice number detected in database.';
}
// 2. بررسی ناهنجاری هوش مصنوعی
else if (aiResult.ai_anomaly_detected === true) {
  finalStatus = 'flagged';
  rejectionReason = `AI Anomaly: ${aiResult.anomaly_reason}`;
}
// 3. بررسی ریاضی ساده (اختیاری، اگر AI انجام نداده باشد)
else if (Math.abs(aiResult.items_sum - aiResult.total_amount) > 0.01) {
  finalStatus = 'flagged';
  rejectionReason = `Math mismatch: Items sum (${aiResult.items_sum}) does not equal Total (${aiResult.total_amount}).`;
}

return [{
  json: {
    vendor_name: aiResult.vendor_name,
    invoice_number: aiResult.invoice_number,
    po_number: aiResult.po_number,
    total_amount: aiResult.total_amount,
    final_status: finalStatus,
    rejection_reason: rejectionReason,
    ai_anomaly_detected: aiResult.ai_anomaly_detected
  }
}];

